/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `tri_student_insert` BEFORE INSERT ON `student` FOR EACH ROW BEGIN
    DECLARE v_user_id BIGINT;

    -- жҸ’е…Ҙ sys_user
    INSERT INTO `sys_user` (
        `dept_id`, `user_name`, `nick_name`, `user_type`,
        `phonenumber`, `sex`, `password`, `status`, `create_time`
    ) VALUES (
                 NULL,
                 NEW.student_id,           -- еӯҰеҸ·дҪңдёәиҙҰеҸ·
                 NEW.name,                 -- е§“еҗҚдҪңдёәжҳөз§°
                 '02',                     -- еӯҰз”ҹз”ЁжҲ·зұ»еһӢ
                 NEW.phone,
                 CASE NEW.gender WHEN 'з”·' THEN '0' WHEN 'еҘі' THEN '1' ELSE '0' END,
                 NEW.password,
                 '0',                      -- зҠ¶жҖҒжӯЈеёё
                 NOW()
             );

    -- иҺ·еҸ–еҲҡжҸ’е…Ҙзҡ„ user_id
    SET v_user_id = LAST_INSERT_ID();

    -- и®ҫзҪ® student иЎЁзҡ„ user_id
    SET NEW.user_id = v_user_id;

    -- иҮӘеҠЁе…іиҒ” role_id=2 зҡ„и§’иүІпјҲжҷ®йҖҡе‘ҳе·Ҙпјү
    INSERT INTO `sys_user_role` (user_id, role_id)
    VALUES (v_user_id, 2);

